121.body:
гҒ•гҒҰгҖҒдёҠгҒ®й …гҒ§гҒӘгӮ“гҒ гҒӢжҖҘгҒ«keymap.setгҒҢгӮ№гғғгӮӯгғӘгҒ—гҒҰиҰӢгҒҲгӮӢгҒ®гҒҜгҖҒгҒ“гҒ®иҫәгӮҠгҒ®и©ұгҒҢй–ўгӮҸгҒЈгҒҰгҒҚгҒҫгҒҷрҹҳҢ дҫӢгҒҲгҒ°гҖҒгҒ“гӮҢгҒҜгӮЁгғ©гғјгҒ«гҒӘгӮҠгҒҫгҒҷгҖӮ Error function testparam(str) print(str)
end vim.keymap.set('n', '<Leader>4', testparam('hello')) гғ‘гғ©гғЎгғјгӮҝгӮ’жёЎгҒҷе ҙеҗҲгҒҜfunction() ~ endгҒ§еӣІгҒЈгҒҰгҒӮгҒ’гҒӘгҒ„гҒЁгҒ„гҒ‘гҒӘгҒ„гӮ“гҒ§гҒҷгҒӯрҹӨ” function testparam(str) print(str)
end vim.keymap.set('n', '<Leader>4', function() testparam('hello') end)

148.body:
гҒ“гӮҢгҒҜе®Ңе…ЁгҒ«иҰӢгҒҹзӣ®гҒ гҒ‘гҒ®гҒҠи©ұгҒӘгӮ“гҒ§гҒҷгҒҢгҖҒгҒ“гӮ“гҒӘгҒ®гҒҢгҒӮгӮҠгҒҫгҒҷгҖӮ Using a floating window You can configure Packer to use a floating window for command outputs by passing a utility function to packer's config: Packer гҒ® config гҒ«гғҰгғјгғҶгӮЈгғӘгғҶгӮЈй–ўж•°гӮ’жёЎгҒҷгҒ“гҒЁгҒ§гҖҒгӮігғһгғігғүеҮәеҠӣгҒ«гғ•гғӯгғјгғҶгӮЈгғігӮ°гӮҰгӮЈгғігғүгӮҰгӮ’дҪҝз”ЁгҒҷгӮӢгӮҲгҒҶгҒ«иЁӯе®ҡгҒҷгӮӢгҒ“гҒЁгҒҢгҒ§гҒҚгҒҫгҒҷгҖӮ е°‘гҒ—гӮігғјгғүгӮ’еӨүгҒҲгҒҰгҒ—гҒҫгҒҶгӮ“гҒ§гҒҷгҒҢгҖҒextensions/init.luaгӮ’д»ҘдёӢгҒ®гӮҲгҒҶгҒ«гҒ—гҒҰгҒҝгҒҫгҒ—гӮҮгҒҶгҖӮ extensions/init.lua require('packer').startup { function() -- '(' гҒӢгӮү '{' гҒ«еӨүгӮҸгҒЈгҒҰгҒҫгҒҷ use 'wbthomason/packer.nvim'
end,
config = { display = { open_fn = function() return require('packer.util').float { border = 'single' } end, }
}} -- ж–Үжі•зҡ„гҒ«еҪ“гҒҹгӮҠеүҚгҒ§гҒҜгҒӮгӮӢгӮ“гҒ§гҒҷгҒҢгҖҒгҒ“гҒ“гӮӮ ')' гҒӢгӮү '}' гҒ«еӨүгӮҸгҒЈгҒҰгҒҫгҒҷ Note дёҠгҒ®дҫӢгҒҜгҒЎгӮҮгҒЈгҒЁеӨүеүҮзҡ„гҒӘгӮӨгғігғҮгғігғҲгҒ«гҒӘгҒЈгҒЎгӮғгҒЈгҒҰгҒҫгҒҷгҒҢгҖҒгҒҚгҒЈгҒЎгӮҠгӮ„гӮӢгҒӘгӮүгҒ“гҒҶгҒ§гҒҷгҖӮгҒҠеҘҪгҒҝгҒ§рҹҳү require('packer').startup { function() use 'wbthomason/packer.nvim' end, config = { display = { open_fn = function() return require('packer.util').float { border = 'single' } end, } }
} гҒӘгӮ“гҒҰгҒ„гҒҶгҒӢ...гҖҒгӮ„гҒЈгҒұ Poisonвҳ пёҸвқ“ гҒ“гҒ®жҜ’гҒҜгӮ«гғ©гғјгғҶгғјгғһгӮ’е…ҘгӮҢгҒЎгӮғгҒҲгҒ°иҮӘз„¶гҒЁжҠңгҒ‘гӮӢгӮ“гҒ§гҖҒ гӮҸгҒҹгҒ—гҒЁгҒ—гҒҰгҒҜгҖҢе°‘гҒ—гҒ®й–“гҒ гҒ‘ж°—гҒ«гҒ—гҒӘгҒ„гҒ§...гҖҚгҒЁиЁҖгҒЈгҒҰгҒ—гҒҫгҒ„гҒҹгҒ„гҒЁгҒ“гӮҚгҒ§гҒҜгҒӮгӮӢгӮ“гҒ§гҒҷгҒҢгҖҒ гҖҢгҒ©гҒҶгҒ—гҒҰгӮӮиҖҗгҒҲгӮүгӮҢгҒӘгҒ„гҖңвқ—гҖҚгҒЈгҒҰгҒ„гҒҶе ҙеҗҲгҒҜгҖҒдёҖеҖӢйЈӣгҒ°гҒ—гҒҰ15.3. onenord.nvimгӮ’е…ҲгҒ«гӮ„гҒЈгҒҰгӮӮгӮүгҒҶгҒЁгҖҒгҒҷгҒҗгҒ«гҒ„гҒ„ж„ҹгҒҳгҒ«гҒӘгӮҠгҒҫгҒҷгҖӮ

155.body:
еүҚй …гҒ®зўәиӘҚгҒ•гҒҲжёҲгӮҒгҒ°гҖҒгҒӮгҒЁгҒҜpackerгҒ«гҒҠйЎҳгҒ„гҒҷгӮӢгҒ гҒ‘гҒ§гҖҢгҒӮгҒЈвқ—гҖҚгҒЁиЁҖгҒҶй–“гҒ«зөӮгӮҸгӮҠгҒҫгҒҷрҹҳҶ extensions/init.luaгҒ«д»ҘдёӢгӮ’иҝҪиЁҳгҒ—гҒҫгҒ—гӮҮгҒҶгҖӮ extensions/init.lua require('packer').startup { function() use 'wbthomason/packer.nvim' -- еүҚзҜҖгҒ§е…ҘгӮҢгҒҹpackerгҒЁеҗҢеҲ—гҒ«дёҰгҒ№гӮӢ use 'nvim-treesitter/nvim-treesitter'
end,
-- (д»ҘдёӢз•Ҙ) гҒ§гҖҒ:PackerSyncгӮ’е®ҹиЎҢгҒ—гҒҫгҒ—гӮҮгҒҶвқ— з°ЎеҚҳгҒ§гҒҷгҒӯрҹҳү гҒҷгҒЈгҒ”гҒ„иҰӢгҒ«гҒҸгҒ„гҒ‘гҒ©вқ— Note nvim-treesitterгҒ®иӘ¬жҳҺгҒ§гҒҜгҖҒ:TSUpdateгӮ’дҪөгҒӣгҒҰиЎҢгҒҶгӮҲгҒҶгҒ«иӘ¬жҳҺгҒ•гӮҢгҒҰгҒ„гӮӢгҒ®гҒ§гҒҷгҒҢгҖҒгҒ“гӮҢгҒҜгҒӮгҒҸгҒҫгҒ§vim-plugгӮ’дҪҝз”ЁгҒ—гҒҰгҒ„гӮӢе ҙеҗҲгҒ®дҫӢгҒ§гҒҷгҖӮ packer.nvimгҒ§гҒҜrunгӮӘгғ—гӮ·гғ§гғігҒ§еҗҢгҒҳгҒ“гҒЁгҒҢгҒ§гҒҚгҒқгҒҶгҒӘгӮ“гҒ§гҒҷгҒҢгҖҒгҒ“гӮҢгӮ’дҪҝз”ЁгҒҷгӮӢгҒЁеҲқеӣһгҒ гҒ‘гӮЁгғ©гғјгҒҢиө·гҒҚгҒҰгҒ—гҒҫгҒҶгҒ®гҒ§гҖҒгӮҸгҒҹгҒ—гҒҜеӨ–гҒ—гҒҰгҒ„гҒҫгҒҷгҖӮ гӮӨгғігӮ№гғҲгғјгғ«иҮӘдҪ“гҒҜ100%гҒ§done.гҒЈгҒҰгҒӘгҒЈгҒҰгӮӢгҒ—гҖҒ2еӣһзӣ®д»ҘйҷҚгҒҜдҪ•дәӢгӮӮгҒӘгҒӢгҒЈгҒҹгҒӢгҒ®гӮҲгҒҶгҒ«:TSUpdateгҒҫгҒ§е®Ңиө°гҒ§гҒҚгӮӢгӮ“гҒ§гҒҷгҒ‘гҒ©гҒӯгҖӮгҒҷгҒЈгҒ”гҒ„иҰӢгҒ«гҒҸгҒ„гҒ‘гҒ©вқ— еҲқеӣһгҒ гҒ‘еӨ–гҒҷгҒӢгҖҒгӮӮгҒ—гҒҸгҒҜж°—гҒ«гҒ—гҒӘгҒ„гҒӢгҒҷгӮӢгҒ®гҒ§гҒӮгӮҢгҒ°и¶…дҫҝеҲ©гҒ§гҒҷгҖӮ use { 'nvim-treesitter/nvim-treesitter', run = ':TSUpdate', }

156.body:
гӮӨгғігӮ№гғҲгғјгғ«гҒҢзөӮгӮҸгҒЈгҒҹгӮүгҖҒж¬ЎгҒ«гӮ„гӮӢгҒ“гҒЁгҒҜгӮігғігғ•гӮЈгӮ°гҒ§гҒҷгҒӯрҹҳҶ Neovimгғ—гғ©гӮ°гӮӨгғігҒ®е ҙеҗҲгҖҒReadmeгҒ§гҒӮгӮӢзЁӢеәҰгғҮгғ•гӮ©гғ«гғҲиЁӯе®ҡгҒҢзӨәгҒ•гӮҢгҒҰгҒ„гҒҰгҖҒ гҒқгӮҢгӮ’еҹәгҒ«гҖҢеӨүгҒҲгӮӢпјҹеӨүгҒҲгҒӘгҒ„пјҹгҖҚгӮ’жұәгӮҒгӮӢгҒҝгҒҹгҒ„гҒӘгҖҒеүІгҒЁгӮўгғҗгӮҰгғҲгҒӘж–№жі•гҒ«гҒ©гҒҶгҒ—гҒҰгӮӮгҒӘгҒЈгҒҰгҒҸгӮӢ...гӮ“гҒҳгӮғгҒӘгҒ„гҒӢгҒӘгҒҒгҒЁжҖқгҒЈгҒҰгӮӢгӮ“гҒ§гҒҷгҒҢгҒ©гҒҶгҒ§гҒ—гӮҮгҒҶвқ“ (йҒ•гҒЈгҒҰгҒҹгӮүгҒ”гӮҒгӮ“гҒӘгҒ•гҒ„рҹҳ…) гҒЁгӮҠгҒӮгҒҲгҒҡгҒҜж–°гҒ—гҒҸгғ•гӮЎгӮӨгғ«гӮ’дҪңгҒЈгҒҰгҒ„гҒҚгҒҫгҒҷгҖӮ гҒ“гӮҢгӮӮгӮ„гҒЈгҒұгӮҠеҗҚеүҚгҒҜдҪ•гҒ§гӮӮиүҜгҒ„гӮ“гҒ§гҒҷгҒҢгҖҒгғ‘гғғгӮұгғјгӮёеҗҚгҒЁжҸғгҒҲгҒҰnvim-treesitter.luaгҒЁгҒ—гҒҰгҒ„гҒҫгҒҷвҳәпёҸ extensions/nvim-treesitter.lua require('nvim-treesitter.configs').setup { ensure_installed = { 'lua' }, sync_install = true, auto_install = true, highlight = { enable = true, }, incremental_selection = { enable = true, keymaps = { init_selection = 'gnn', node_incremental = 'grn', scope_incremental = 'grc', node_decremental = 'grm', }, }, indent = { enable = true, },
} гҒқгҒ—гҒҰгҖҒгҒ“гӮҢгӮ’packerгҒ®з®ЎзҗҶдёӢгҒ«зҪ®гҒ„гҒҰдҪҝгҒ„гҒҫгҒҷгҖӮе…ҲгҒ»гҒ©жӣёгҒ„гҒҹnvim-treesitterгҒ®иӘӯгҒҝиҫјгҒҝйғЁеҲҶгӮ’е°‘гҒ—жӣёгҒҚжҸӣгҒҲгҒҫгҒҷгҖӮ extensions/init.lua require('packer').startup { function() use 'wbthomason/packer.nvim' -- гҒ“гӮ“гҒӘж„ҹгҒҳгҒ§гҖӮ use { 'nvim-treesitter/nvim-treesitter', config = function() require 'extensions.nvim-treesitter' end, }
end,
-- (д»ҘдёӢз•Ҙ) :h packer.use() config = string or function, -- Specifies code to run after this plugin is loaded. гҒ“гҒ®гғ—гғ©гӮ°гӮӨгғігҒҢгғӯгғјгғүгҒ•гӮҢгҒҹеҫҢгҒ«е®ҹиЎҢгҒҷгӮӢгӮігғјгғүгӮ’жҢҮе®ҡгҒ—гҒҫгҒҷгҖӮ еҶҚиө·еӢ•гӮӮгҒ—гҒҸгҒҜ:soгҒ§гҒ“гҒ®зҠ¶ж…ӢгӮ’еҸҚжҳ гҒ•гҒӣгҒҰгҒӢгӮүPackerSyncгӮӮгҒ—гҒҸгҒҜPackerCompileгӮ’е®ҹиЎҢгҒ—гҒҫгҒ—гӮҮгҒҶгҖӮ гҒҷгӮӢгҒЁгҖҒnvim-treesitterгҒҢеӢ•гҒ„гҒҰгҖҒжңҖзөӮзҡ„гҒ«гҒ“гӮ“гҒӘгҒ®гҒҢеҮәгҒҰгҒҚгҒҫгҒ—гҒҹгҖӮ гҒ“гӮҢгҒ§гҖҒluaгғ•гӮЎгӮӨгғ«гҒҢд»ҠгҒҫгҒ§гӮҲгӮҠгӮӮиіўгҒҸиүІд»ҳгҒ‘гҒ•гӮҢгҒҰгӮӢгҒҜгҒҡгҒ§гҒҷгҖӮгҒ©гҒҶгҒ§гҒ—гӮҮгҒҶвқ“ Note ensure_installedгҒ§жҢҮе®ҡгҒ—гҒҹиЁҖиӘһгғ‘гғјгӮөгҒ®гӮӨгғігӮ№гғҲгғјгғ«гҒҢиЎҢгӮҸгӮҢгӮӢгҒҜгҒҡгҒӘгҒ®гҒ§гҖҒгҒқгӮҢгҒ«гӮҲгҒЈгҒҰгҒҜе°‘гҒ—иЎЁзӨәгҒҢеӨүгӮҸгӮҠгҒҫгҒҷгҖӮ Warning гӮӮгҒ—гҒ“гҒ“гҒ§гӮЁгғ©гғјгҒҢиө·гҒҚгӮӢгӮҲгҒҶгҒ§гҒӮгӮҢгҒ°гҖҒгӮӮгҒҶдёҖеәҰC compilerгӮ’зўәиӘҚгҒ—гҒҰгҒҝгҒҰгҒҸгҒ гҒ•гҒ„рҹҳЈ default nvim-treesitter Note гҒ“гӮҢгҒҜдҫӢгҒҢйқўзҷҪгҒҸгҒӘгҒ„гҒ®гҒ§гҒӮгӮҢгҒӘгӮ“гҒ§гҒҷгҒҢгҖҒгӮӘгғ•гӮЈгӮ·гғЈгғ«гӮӨгғЎгғјгӮёгӮ’иҰӢгӮӢгҒЁгҒ“гӮ“гҒӘгҒ«еӨүгӮҸгҒЈгҒҰгҒҫгҒҷвқ— nvim-treesitter/wiki/Gallery ...гҒӮгҒЈгҒЎгҒ§гӮӮluaгҒҜеӨүеҢ–гҒҢгӮҸгҒӢгӮҠгҒ«гҒ„гӮ“гҒ§гҒҷгҒ‘гҒ©гҒӯрҹҳ…

162.body:
`false` will disable the whole extension false` гӮ’жҢҮе®ҡгҒҷгӮӢгҒЁгҖҒжӢЎејөж©ҹиғҪе…ЁдҪ“гӮ’з„ЎеҠ№гҒ«гҒҷгӮӢгҒ“гҒЁгҒҢгҒ§гҒҚгҒҫгҒҷгҖӮ гҒЁгҖҒгҒ„гҒҶгҒ“гҒЁгҒӘгҒ®гҒ§гҖҒ highlight = { enable = false
} ...гҒӘгӮ“гҒҰгҒ—гҒЎгӮғгҒҲгҒ°жӢЎејөж©ҹиғҪе…ЁдҪ“гӮ’з„ЎеҠ№гҒ«гҒ—гҒҫгҒҷгҖӮгҒ„гӮ„гҖҒгҒӣгҒЈгҒӢгҒҸе…ҘгӮҢгҒҹгҒ®гҒ§trueгҒ«гҒ—гҒҫгҒ—гӮҮвқ“ гҒЎгҒӘгҒҝгҒ«disableгӮӘгғ—гӮ·гғ§гғігӮ’дҪҝгҒҶгҒЁгҖҒзү№е®ҡгҒ®иЁҖиӘһгҒ гҒ‘йҒёгӮ“гҒ§йҷӨеӨ–гҒ§гҒҚгҒҫгҒҷгҖӮ highlight = { enable = true, disable = { "c", "rust" },
},

173.body:
Style that is applied to various groups: see `highlight-args` for options ж§ҳгҖ…гҒӘгӮ°гғ«гғјгғ—гҒ«йҒ©з”ЁгҒ•гӮҢгӮӢгӮ№гӮҝгӮӨгғ«: гӮӘгғ—гӮ·гғ§гғігҒҜ `:h highlight-args` гӮ’еҸӮз…§гҒ—гҒҰгҒҸгҒ гҒ•гҒ„гҖӮ -- д»ҘдёӢгҒҜгғҮгғ•гӮ©гғ«гғҲеҖӨгҒ§гҒҷгҖӮ
