гӮҸгҒҹгҒ—гҒҢдҪҝгҒЈгҒҰгҒ„гӮӢгҒ®гҒҜгӮӯгғјгғңгғјгғүзҠ¶ж…ӢгҒ§гҒҷгҖӮгҒІгҒЁгҒҫгҒҡгӮігғјгғүгҒҜгҒ“гӮ“гҒӘж„ҹгҒҳгҖӮ status.lua local DEFAULT_FG = { Color = '#9a9eab' }
local DEFAULT_BG = { Color = '#333333' } local SPACE_1 = ' '
local SPACE_3 = ' ' local HEADER_KEY_NORMAL = { Foreground = DEFAULT_FG, Text = 'оӘ“' }
local HEADER_LEADER = { Foreground = { Color = '#ffffff' }, Text = 'о©Ҙ' }
local HEADER_IME = { Foreground = DEFAULT_FG, Text = 'гҒӮ' } local function AddIcon(elems, icon) table.insert(elems, { Foreground = icon.Foreground }) table.insert(elems, { Background = DEFAULT_BG }) table.insert(elems, { Text = SPACE_1 .. icon.Text .. SPACE_3 })
end local function GetKeyboard(elems, window) if window:leader_is_active() then AddIcon(elems, HEADER_LEADER) return end AddIcon(elems, window:composition_status() and HEADER_IME or HEADER_KEY_NORMAL)
end SPACE_3гҒЁгҒӢгҒҜиҮӘеҲҶгҒ§гӮӮгҒЎгӮҮгҒЈгҒЁгғһгғҢгӮұгҒ гҒЁгҒҜжҖқгҒЈгҒҰгҒҫгҒҷгҒҢгҖҒгҒӘгӮ“гҒӢгҒ”гӮҒгӮ“гҒӘгҒ•гҒ„...рҹҳҝ гҒҫгҒ update-statusгҒЁз№ӢгҒ„гҒ§гҒӘгҒ„гҒ®гҒ§еӢ•гҒҚгҒҫгҒӣгӮ“гҒҢгҖҒгҒ“гҒ“гҒ§дёҖж—ҰеҢәеҲҮгҒЈгҒҰиЈңи¶ігҒ—гҒҫгҒҷгҖӮ гҒ“гҒ“гҒ§гҒҜд»ҘдёӢгҒ®зҠ¶ж…ӢгӮ’еҸҜиҰ–еҢ–гҒ—гҒҫгҒҷгҖӮ leaderгӮӯгғјгӮўгӮҜгғҶгӮЈгғ– IME

