}, Default Configuration гӮ’иҰӢгҒҰгҒ®йҖҡгӮҠгҖҒ гғҮгғ•гӮ©гғ«гғҲгҒ§гҒҜnilгҒ«гҒӘгҒЈгҒҰгҒ„гӮӢгҒ®гҒ§гҖҒгҒ“гӮҢгӮ’ArrayгҒ§гӮӘгғјгғҗгғјгғ©гӮӨгғүгҒ—гҒҰгҒ„гҒҫгҒҷгҖӮ Note гҒұгҒЈгҒЁиҰӢгҒҹж„ҹгҒҳгҖҒhandlersгҒ«еҜҫгҒ—гҒҰгҖҢгҒӘгӮ“гӮ„гҒ“гҒ„гҒӨрҹҳ®гҖҚгҒЁжҖқгӮҸгҒӘгҒҸгӮӮгҒӘгҒ„гӮ“гҒ§гҒҷгҒҢгҖҒгҒ“гӮҢгҒӘгҒ„гҒЁеӢ•гҒӢгҒӘгҒ„гҒ§гҒ—гӮҮвқ“

48.body:
гҒҫгҒҡгҒҜ wez гҒ•гӮ“гҒ®гӮөгғігғ—гғ«гӮігғјгғүгӮ’гҒ»гҒјдёёеҶҷгҒ—гҒ§гҒҷгҒҢгҖҒдёҖгҒӨгҒҡгҒӨж©ҹиғҪгӮ’еҲҶгҒ‘гҒҫгҒҷгҖӮ Warning е…ҲгҒ«дёӢиЁҳгҒ®гӮігғјгғүгӮ’ијүгҒӣгҒҰгҒ„гҒҫгҒҷгҒҢгҖҒгҒ„гҒҸгҒӨгҒӢжңӘе®ҡзҫ©гҒӘгӮӮгҒ®гҒҢгҒӮгӮӢгҒ®гҒ§гҖҒгҒ“гӮҢгҒ гҒ‘гҒ гҒЁгӮЁгғ©гғјгҒ«гҒӘгҒЈгҒЎгӮғгҒ„гҒҫгҒҷгҖӮ status.lua local function GetHostAndCwd(elems, pane) local uri = pane:get_current_working_dir() if not uri then return end local cwd_uri = uri:sub(8) local slash = cwd_uri:find '/' if not slash then return end local host = cwd_uri:sub(1, slash - 1) local dot = host:find '[.]' AddElement(elems, HEADER_HOST, dot and host:sub(1, dot - 1) or host) AddElement(elems, HEADER_CWD, cwd_uri:sub(slash))
end local function GetDate(elems) AddElement(elems, HEADER_DATE, wezterm.strftime '%a %b %-d')
end local function GetTime(elems) AddElement(elems, HEADER_TIME, wezterm.strftime '%H:%M')
end local function GetBattery(elems, window) if not window:get_dimensions().is_full_screen then return end for _, b in ipairs(wezterm.battery_info()) do AddElement(elems, HEADER_BATTERY, string.format('%.0f%%', b.state_of_charge * 100)) end
end wez гҒ•гӮ“гҒ®гӮөгғігғ—гғ«гҒ§гҒҜдёҖеәҰгҒ«еҸ–еҫ—гҒ—гҒҰгҒ„гҒҹdateгҒЁtimeгӮӮеҲҶгҒ‘гҒЎгӮғгҒЈгҒҰгҒҫгҒҷгҖӮ зЁӢеәҰгҒҜеҲҶгҒӢгӮҠгҒҫгҒӣгӮ“гҒҢгҖҒйқһеҠ№зҺҮгҒ§гҒҜгҒӮгӮӢгҒЁжҖқгӮҸгӮҢгӮӢгҒ®гҒ§гҒҠеҘҪгҒҝгҒ§рҹҳү гғҗгғғгғҶгғӘгғјиЎЁзӨәгҒ«гҒӨгҒ„гҒҰгҒҜгҖҒгӮҸгҒҹгҒ—гҒ®е ҙеҗҲгҒҜгғ•гғ«гӮ№гӮҜгғӘгғјгғігҒ®жҷӮгҒ гҒ‘еҮәгҒ—гҒҰгҒ„гҒҫгҒҷгҖӮгӮ№гӮҜгғӘгғјгғізҠ¶ж…ӢгҒҜдёӢиЁҳгҒ§еҸ–еҫ—гҒ§гҒҚгҒҫгҒҷгҖӮ window:get_dimensions() The table has the following fields: pixel_width: the width of the window in pixels pixel_height: the height of the window in pixels dpi: The DPI of the screen the window in on is_full_screen: whether the window is in full screen mode гғҶгғјгғ–гғ«гҒ«гҒҜд»ҘдёӢгҒ®гғ•гӮЈгғјгғ«гғүгҒҢгҒӮгӮҠгҒҫгҒҷ: pixel_width: гғ”гӮҜгӮ»гғ«еҚҳдҪҚгҒ®гӮҰгӮЈгғігғүгӮҰгҒ®е№… pixel_height: гғ”гӮҜгӮ»гғ«еҚҳдҪҚгҒ§иЎЁгҒ—гҒҹгӮҰгӮЈгғігғүгӮҰгҒ®й«ҳгҒ• dpi: гӮҰгӮЈгғігғүгӮҰгҒҢиЎЁзӨәгҒ•гӮҢгҒҰгҒ„гӮӢгӮ№гӮҜгғӘгғјгғігҒ® DPI is_full_screen: гӮҰгӮЈгғігғүгӮҰгҒҢгғ•гғ«гӮ№гӮҜгғӘгғјгғігғўгғјгғүгҒ§гҒӮгӮӢгҒӢгҒ©гҒҶгҒӢ гҒ“гҒ“гҒ§гҒҜis_full_screenгӮ’дҪҝгҒ„гҒҫгҒҷгҖӮгғ•гғ«гӮ№гӮҜгғӘгғјгғіжҷӮгҒҜtrueгҒҢиҝ”гӮҠгҒҫгҒҷгҖӮ Note OSгҒӢгӮүгҒ®гғ•гғ«гӮ№гӮҜгғӘгғјгғіж“ҚдҪңгҖҒгӮӮгҒ—гҒҸгҒҜ WezTermгҒ® ToggleFullScreen гҒ«еҸҚеҝңгҒ—гҒҫгҒҷгҖӮ (д»ҘеүҚгҖҒToggleFullScreenгҒ гҒЁеҸҚеҝңгҒ—гҒӘгҒ„гҒЁжӣёгҒ„гҒҰгҒ„гҒҫгҒ—гҒҹгҒҢгҖҒд»ҠиҰӢгҒҹгӮүгҒЎгӮғгӮ“гҒЁеӢ•гҒ„гҒҰгҒҫгҒ—гҒҹвҳәпёҸ) гҒ§гҖҒд»ҘдёӢгҒҢи¶ігӮҠгҒҰгҒ„гҒӘгҒӢгҒЈгҒҹе®ҡзҫ©гҒ§гҒҷгҖӮ status.lua local HEADER_HOST = { Foreground = { Color = '#75b1a9' }, Text = 'пү¬' }
local HEADER_CWD = { Foreground = { Color = '#92aac7' }, Text = 'пҒј' }
local HEADER_DATE = { Foreground = { Color = '#ffccac' }, Text = 'уұӘә' }
local HEADER_TIME = { Foreground = { Color = '#bcbabe' }, Text = 'оҷҒ' }
local HEADER_BATTERY = { Foreground = { Color = '#dfe166' }, Text = 'пүҒ' } local function AddElement(elems, header, str) table.insert(elems, { Foreground = header.Foreground }) table.insert(elems, { Background = DEFAULT_BG }) table.insert(elems, { Text = header.Text .. SPACE_1 }) table.insert(elems, { Foreground = DEFAULT_FG }) table.insert(elems, { Background = DEFAULT_BG }) table.insert(elems, { Text = str .. SPACE_3 })
end (еүҚгҒ®гғҡгғјгӮёгҒ§жӣёгҒ„гҒҹе®ҡзҫ©гӮӮдҪҝз”ЁгҒ—гҒҰгҒ„гӮӢгҒ®гҒ§гҖҒз„ЎгҒӢгҒЈгҒҹгӮүд»ҘдёӢгӮӮиҝҪиЁҳгҒ—гҒҰгҒҸгҒ гҒ•гҒ„гҖӮ) local DEFAULT_FG = { Color = '#9a9eab' }
local DEFAULT_BG = { Color = '#333333' } local SPACE_1 = ' '
local SPACE_3 = ' ' еј•гҒЈејөгҒЈгҒҹеүІгҒ«гҒҜзү№гҒ«гӮігғЎгғігғҲгҒҷгӮӢгҒЁгҒ“гӮҚгӮӮгҒӘгҒ„гҒ§гҒҷгҒӯ...гҖӮгҒқгҒ®гҒҫгҒҫе®ҢжҲҗгҒ•гҒӣгҒЎгӮғгҒ„гҒҫгҒ—гӮҮгҒҶрҹҳҠ status.lua local function RightUpdate(window, pane) local elems = {} GetHostAndCwd(elems, pane) GetDate(elems) GetBattery(elems, window) GetTime(elems) window:set_right_status(wezterm.format(elems))
end wezterm.on('update-status', function(window, pane) LeftUpdate(window, pane) -- еүҚеӣһжӣёгҒ„гҒҹгӮігғјгғүгҒҜгҒқгҒ®гҒҫгҒҫгҒ§гҖӮ RightUpdate(window, pane)
end) гҒ•гҒҰгҖҒгҒ“гӮҢгҒ§гҒ“гӮ“гҒӘж„ҹгҒҳгҒ«гҒӘгҒЈгҒҹгҒҜгҒҡгҒӘгӮ“гҒ§гҒҷгҒҢгҒ©гҒҶгҒ§гҒ—гӮҮгҒҶвқ“(дҫӢгҒ«гӮҲгҒЈгҒҰгғҰгғјгӮ¶гғјеҗҚгҒҜйӣ‘гҒ«йҡ гҒ—гҒҰгҒҫгҒҷгҖӮ) гғ•гғ«гӮ№гӮҜгғӘгғјгғіжҷӮгҒ«гҒҜгғҗгғғгғҶгғӘгғјиЎЁзӨәгҒҢгҒ•гӮҢгҒҰгҒ„гӮӢгҒ“гҒЁгӮӮзўәиӘҚгҒ§гҒҚгҒҫгҒҷгҖӮ Success иҸҜгӮ„гҒӢгҒ«гҒӘгӮҠгҒҫгҒ—гҒҹгҒӯвҳәпёҸ (гҒҫгҒӮгҖҒгҒ¶гҒЈгҒЎгӮғгҒ‘гҒқгӮ“гҒӘиҰӢгҒӘгҒ„гӮ“гҒ гҒ‘гҒ©...) гӮөгғігғ—гғ«йҖҡгӮҠгҒЁгҒҜгҒ„гҒҲгҖҒиҮӘеҲҶгҒ§жӣёгҒ„гҒҹгӮігғјгғүгҒҢеӢ•гҒҸгӮ“гҒ гҒӢгӮүжҘҪгҒ—гҒ„дё–з•ҢгҒ§гҒҷгҖӮгҒ»гӮҸгҒ»гӮҸгҖңрҹ’•

485.body:
гҒЎгӮҮгҒЈгҒЁгҒ гҒ‘ гӮҖгҒӢгҖңгҒ—гҖҒгӮҖгҒӢгҒ—гҒ®гҒҠгҒ•гӮүгҒ„гҖӮ extensions/mason.lua require('mason').setup { ui = { check_outdated_packages_on_open = false, border = 'single', },
} require('mason-lspconfig').setup_handlers { function(server_name) require('lspconfig')[server_name].setup { capabilities = require('cmp_nvim_lsp').default_capabilities(), } end,
} еӣәжңүгҒ®иЁӯе®ҡгӮ’еҝ…иҰҒгҒЁгҒ—гҒӘгҒ‘гӮҢгҒ°гҖҒ гҒ“гӮҢгҒ гҒ‘гҒ§mason.nvimгҒ§гӮӨгғігӮ№гғҲгғјгғ«гҒ—гҒҹLSPгҒҜе…ЁгҒҰгӮ«гғҗгғјгҒ§гҒҚгҒҰгҒ„гҒҫгҒ—гҒҹгҒӯрҹҳҶ Tip гҒ“гҒ®гӮөгӮӨгғҲгҒ§гҒҜpackerгҒЁеӨ–иҰігҒ®зөұдёҖж„ҹгӮ’жҢҒгҒҹгҒӣгӮӢзӣ®зҡ„гҒ§masonгҒ« border гӮ’е…ҘгӮҢгҒҰгҒ„гҒҫгҒ—гҒҹгҖӮ lazyгӮ’дҪҝгҒҶе ҙеҗҲгҖҒгҒ“гӮҢгҒҜгӮӮгҒҶз„ЎгҒ„гҒ»гҒҶгҒҢзөұдёҖж„ҹгҒҢеҮәгҒҰгҒ„гҒ„гҒӢгӮӮгҖңрҹҳӘ require('mason').setup { ui = { check_outdated_packages_on_open = false,
- border = 'single', },
} иў–жҢҜгӮҠеҗҲгҒҶгӮӮд»–з”ҹгҒ®зёҒпјҒ иә“гҒҸзҹігӮӮзёҒгҒ®з«ҜгҒҸгӮҢпјҒ

489.body:
еҶ’йҷәгҒҜгҒ„гҒӨгҒ гҒЈгҒҰгғҜгғігҒ гҒөгӮӢ rust-analyzer rust-analyzer is a modular compiler frontend for the Rust language. It is a part of a larger rls-2.0 effort to create excellent IDE support for Rust. rust-analyzer гҒҜгҖҒRust иЁҖиӘһз”ЁгҒ®гғўгӮёгғҘгғ©гғјгғ»гӮігғігғ‘гӮӨгғ©гғ»гғ•гғӯгғігғҲгӮЁгғігғүгҒ§гҒҷгҖӮ Rust гҒ®е„ӘгӮҢгҒҹ IDE гӮөгғқгғјгғҲгӮ’дҪңжҲҗгҒҷгӮӢгҒҹгӮҒгҒ®гҖҒгӮҲгӮҠеӨ§гҒҚгҒӘ rls-2.0 гҒ®еҸ–гӮҠзө„гҒҝгҒ®дёҖйғЁгҒ§гҒҷгҖӮ гҒЁгҖҒгҒ„гҒҶгҒ“гҒЁгҒ§RustгҒ«гҒҜгҒ“гӮҢгҒҢгҒ„гҒ„гӮ“гҒҳгӮғгҒӘгҒ„гҒӢгҒЁжҖқгҒҶгӮ“гҒ гҒ‘гҒ©гҖҒ гҒ©гҒ“гӮ’иҰӢгҒҰжҢҒгҒЈгҒҰгҒҚгҒҹгҒ®гҒӢгҒҢжҖқгҒ„еҮәгҒӣгҒӘгҒҸгҒҰиҰӢгҒӨгҒӢгӮүгҒӘгҒ„...рҹҳ‘ extensions/mason.lua ['rust_analyzer'] = function() lsp.rust_analyzer.setup { settings = { ['rust-analyzer'] = { diagnostic = { enable = false }, assist = { importGranularity = 'module', importPrefix = 'self' }, cargo = { allFeatures = true, loadOutDirsFromCheck = true }, procMacro = { enable = true }, }, }, }
end, рҹҗҰ Clippy з№ӢгҒҢгҒЈгҒҰгҒҸзёҒгҒЁзёҒ еҮәдјҡгҒ„гҒҜе°‘гҒ—гғҲгғӘгғғгӮӯгғј Clippy A collection of lints to catch common mistakes and improve your Rust code. There are over 700 lints included in this crate! Lints are divided into categories, each with a default lint level . You can choose how much Clippy is supposed to annoy help you by changing the lint level by category гӮҲгҒҸгҒӮгӮӢгғҹгӮ№гӮ’зҷәиҰӢгҒ—гҖҒгҒӮгҒӘгҒҹгҒ® Rust гӮігғјгғүгӮ’ж”№е–„гҒҷгӮӢгҒҹгӮҒгҒ® lint гҒ®гӮігғ¬гӮҜгӮ·гғ§гғігҒ§гҒҷгҖӮ гҒ“гҒ® crate гҒ«гҒҜ 700д»ҘдёҠгҒ®гғӘгғігғҲгҒҢеҗ«гҒҫгӮҢгҒҰгҒ„гҒҫгҒҷпјҒ Lints гҒҜгӮ«гғҶгӮҙгғӘгҒ«еҲҶгҒӢгӮҢгҒҰгҒҠгӮҠгҖҒ гҒқгӮҢгҒһгӮҢгғҮгғ•гӮ©гғ«гғҲгҒ® lint level гӮ’жҢҒгҒЈгҒҰгҒ„гҒҫгҒҷгҖӮ гӮ«гғҶгӮҙгғӘгҒ”гҒЁгҒ« lint level гӮ’еӨүжӣҙгҒҷгӮӢгҒ“гҒЁгҒ§гҖҒClippy гҒҢгҒ©гҒ®зЁӢеәҰгҒӮгҒӘгҒҹгӮ’ иҝ·жғ‘ жүӢеҠ©гҒ‘гҒҷгӮӢгҒӢгӮ’йҒёжҠһгҒ§гҒҚгҒҫгҒҷгҖӮ гҒ“гӮҢгҒҜгҒЎгӮҮгҒЈгҒЁзўәиӘҚгҒ—гҒҰгҒӘгҒ„гӮ“гҒ§гҒҷгҒҢгҖҒ ClippyгҒҜmason.nvimгҒӢгӮүгҒҜе…ҘгӮүгҒӘгҒ„гӮ“гҒҳгӮғгҒӘгҒ„гҒӢгҒӘвқ“ RustгҒ®з’°еўғгӮ’е…ҘгӮҢгӮӢгҒЁгҖҒгҒҹгҒ¶гӮ“иҮӘз„¶гҒ«гӮӨгғігӮ№гғҲгғјгғ«гҒ•гӮҢгҒҰгӮӢгӮ„гҒӨгҒ§гҒҷгҖӮ extensions/mason.lua ['rust_analyzer'] = function() lsp.rust_analyzer.setup { settings = { ['rust-analyzer'] = { diagnostic = { enable = false }, assist = { importGranularity = 'module', importPrefix = 'self' }, cargo = { allFeatures = true, loadOutDirsFromCheck = true }, procMacro = { enable = true },
+ checkOnSave = { allFeatures = true, command = 'clippy' }, }, }, } end, гҒ“гӮ“гҒӘж„ҹгҒҳгҒ§гҖҒrustcгҒ«ж··гҒҳгҒЈгҒҰclippyгӮӮжҖ’гӮӢгӮҲгҒҶгҒ«гҒӘгӮҠгҒҫгҒҷрҹҳұ

513.body:
гғ•гӮ©гғігғҲгҒ«гҒӨгҒ„гҒҰгҒҜгҖҒгҒ“гҒ®гӮөгӮӨгғҲгҒ§гҒҜд»ҘдёӢгҒ®гӮҲгҒҶгҒ«зҙ№д»ӢгҒ—гҒҰгҒ„гҒҫгҒ—гҒҹгҖӮ font = require("wezterm").font("Firge35Nerd Console"), зү№гҒ«дёҚжәҖгҒҢгҒӘгҒ‘гӮҢгҒ°гҒ“гҒ®гҒҫгҒҫгҒ§гӮӮгҒ„гҒ„гӮ“гҒ§гҒҷгҒҢгҖҒ жңҖж–°гҒ®гғ•гӮ©гғігғҲгӮ’иҮӘеҲҶгҒ§иҝҪгҒЈгҒӢгҒ‘гҒҹгҒ„е ҙеҗҲгҒӘгӮ“гҒӢгҒ гҒЁгҖҒеҫҢгҒ®й …гҒ§еҮәгҒҰгҒҸгӮӢfont_with_fall_backгӮ’дҪҝгҒҶгҒЁиүҜгҒ„гҒ§гҒҷгҖӮ вӣІ FontSets ...гҒЈгҒҰгҒ“гҒЁгҒ§гҖҒгҒҫгҒҡгҒҜгғ•гӮ©гғігғҲгӮ’з”Ёж„ҸгҒ—гҒҫгҒ—гӮҮгҒҶвқ— Note жңҖеҫҢгҒ«гҒ—гҒҰгҖҒгҒӘгҒңгҒӢжңҖеҲқгҒ®жқ‘гҒҝгҒҹгҒ„гҒӘгӮ»гғӘгғ•гӮ’гҒӮгӮүгҒӢгҒҳгӮҒ...гҖӮ гҖҢгғҖгӮҰгғігғӯгғјгғүгҒ—гҒҹгғ•гӮ©гғігғҲгҒҜгӮӨгғігӮ№гғҲгғјгғ«гҒ—гҒӘгҒ„гҒЁдҪҝгҒҲгҒӘгҒ„гҒһвқ—вқ—гҖҚ рҹӘә nerd-fonts nerd-fontsгҒҜWezTermгҒ«еҗ«гҒҫгӮҢгҒҰгҒ„гӮӢгҒ®гҒ§зү№гҒ«иЁӯе®ҡгҒҜгҒ„гӮүгҒӘгҒ„гӮ“гҒ гҒ‘гҒ©гҖҒ еүҚеӣһ гҒҜNerd FontгҒҢеҗ«гҒҫгӮҢгҒҰгҒ„гӮӢFirgeNerdгӮ’дҪҝгҒҶж–№жі•гӮ’зҙ№д»ӢгҒ—гҒҰгҒ„гҒҫгҒ—гҒҹгҖӮ 2024/04/17 жҷӮзӮ№гҒ§гҒҜFirgeNerdгғ»WezTermгҒ®гҒ©гҒЎгӮүгӮҲгӮҠгӮӮгҖҒ жң¬е®¶гҒ®nerd-fontsгҒ®гғҗгғјгӮёгғ§гғігҒҜгҒ гҒ„гҒ¶йҖІгӮ“гҒ§гҒ„гҒҰгҖҒ ж–°гҒ—гҒ„гӮўгӮӨгӮігғігӮӮз¶ҡгҖ…гҒЁеў—гҒҲгҒҰгҒ„гӮӢгҒ®гҒ§гҖҒе®ҡжңҹзҡ„гҒ«зўәиӘҚгҒ—гҒҰгҒҝгӮӢгҒ®гӮӮжҘҪгҒ—гҒ„гҒЁжҖқгҒ„гҒҫгҒҷрҹҳҶ Note 2025/02/10 гҒ«WezTermжң¬дҪ“гҒ«еҗ«гҒҫгӮҢгӮӢnerd-fontsгҒҢv3.3.0гҒ«гӮўгғғгғ—гғҮгғјгғҲгҒ•гӮҢгҒҹгҒқгҒҶгҒ§гҒҷвқ— зҸҫжҷӮзӮ№гҒ§жңҖж–°гҒ®nightly buildгӮ’дҪҝз”ЁгҒ—гҒҰгҒ„гӮӢе ҙеҗҲгҖҒд»ҘдёӢгҒ®жүӢй ҶгҒҜеҝ…иҰҒгҒӮгӮҠгҒҫгҒӣгӮ“рҹҗӨ WezTermгӮӮnerd-fontsгӮӮйҖІжӯ©гӮ’з¶ҡгҒ‘гҒҰгҒ„гӮӢгҒ®гҒ§гҖҒгҒЁгҒҰгӮӮй јгӮӮгҒ—гҒ„гҒ§гҒҷгҒӯрҹҳё гҒ гҒ„гҒ¶жҷӮжңҹгҒҜйҒҺгҒҺгҒҰгӮӢгҒ‘гҒ© Happy Haloween!! рҹҺғ гҒЈгҒҰгҒ“гҒЁгҒ§гҖҒд»ҠеӣһгҒҜжң¬е®¶гҒ®nerd-fontsгӮ’дҪҝгҒЈгҒҹжҘҪгҒ—гҒ„гҒ»гҒҶгҒ§йҖІгӮҒгҒҫгҒҷгҖӮ Releases / v3.2.0 The Easter release. Lets see which eggs can be found: гӮӨгғјгӮ№гӮҝгғјгғӘгғӘгғјгӮ№гҒ гӮҲгҖӮгҒ©гӮ“гҒӘеҚөгҒҢиҰӢгҒӨгҒӢгӮӢгҒӢгҒӘ: Releases гҒӢгӮүж„ҹи¬қгҒ—гҒӘгҒҢгӮүжңҖж–°зүҲгӮ’гғҖгӮҰгғігғӯгғјгғүгҒ—гҒҫгҒ—гӮҮгҒҶрҹҳү еҘҪгҒҚгҒӘгҒҹгҒҫгҒ”рҹҘҡ гӮ’йҒёгҒ№гҒ°иүҜгҒ„гҒ®гҒ§гҒҷгҒҢгҖҒгҒ“гҒ®гғҡгғјгӮёгҒ§гҒҜNerdFontsSymbolsOnlyгӮ’дҪҝгҒЈгҒҰйҖІгӮҒгҒҰгҒ„гҒҚгҒҫгҒҷгҖӮ Tip NerdFontsSymbolsOnly.tar.xzгӮӮгҒ—гҒҸгҒҜNerdFontsSymbolsOnly.zipгҒҜгҖҒж–Үеӯ—йҖҡгӮҠгӮ·гғігғңгғ«гӮӘгғігғӘгғјгҒ§гҒҷрҹҗЈ вқӨпёҸвҖҚрҹ”Ҙ FiraCode гҒ§гҖҒж¬ЎгҒ«иӢұеӯ—гғ•гӮ©гғігғҲгӮ’з”Ёж„ҸгҒҷгӮӢгӮ“гҒ§гҒҷгҒҢгҖҒгҒ“гҒ“гҒ§гҒҜдёҖдҫӢгҒЁгҒ—гҒҰFiraCodeгӮ’зҙ№д»ӢгҒ—гҒҫгҒҷгҖӮ FiraCode Fira Code: free monospaced font with programming ligatures Fira Code: гғ—гғӯгӮ°гғ©гғҹгғігӮ°еҗҲеӯ—гҒ®гғ•гғӘгғјзӯүе№…гғ•гӮ©гғігғҲ гҒ“гӮҢгӮӮзҙ зӣҙгҒ« Releases гҒӢгӮүж„ҹи¬қгҒ—гҒӘгҒҢгӮүгғҖгӮҰгғігғӯгғјгғүгҒҷгӮӢгҒ®гҒҢз°ЎеҚҳгҒ§гҒ—гӮҮгҒҶрҹҳҠ рҹҺҸ гғ’гғ©гӮ®гғҺи§’гӮҙгӮ·гғғгӮҜ гҒ“гӮҢгҒ гҒ‘гҒ гҒЁ "жјўеӯ—гғ»гҒІгӮүгҒҢгҒӘгғ»гӮ«гӮҝгӮ«гғҠ" гҒҢгӮӨгғһгӮӨгғҒгҒ«жҲ»гҒЈгҒЎгӮғгҒҶгҒ®гҒ§гҖҒж—Ҙжң¬иӘһгҒ«еҜҫеҝңгҒ—гҒҹгғ•гӮ©гғігғҲгӮӮз”Ёж„ҸгҒ—гҒҫгҒ—гӮҮгҒҶгҖӮ гӮҸгҒҹгҒ—гҒҜmacOSгҒ«жЁҷжә–гҒ§е…ҘгҒЈгҒҰгҒ„гӮӢгғ’гғ©гӮ®гғҺи§’гӮҙгӮ·гғғгӮҜгӮ’дҪҝгҒЈгҒҰгҒ„гӮӢгҒ®гҒ§гҖҒгҒ“гҒ“гҒ§гҒҜзү№гҒ«зӨәгҒӣгӮӢжүӢй ҶгҒҢгҒӮгӮҠгҒҫгҒӣгӮ“рҹҳ… рҹҗЈ font_with_fall_back гғ•гӮ©гғігғҲгҒҢз”Ёж„ҸгҒ§гҒҚгҒҹгӮүгҖҒгҒ“гӮҢгӮүгӮ’WezTermгҒ§дҪҝгҒҶгҒҹгӮҒгҒ«font_with_fall_backгӮ’иЁӯе®ҡгҒ—гҒҫгҒ—гӮҮгҒҶвқ— wezterm.font_with_fallback(families [, attributes]) This function constructs a lua table that configures a font with fallback processing. Glyphs are looked up in the first font in the list but if missing the next font is checked and so on. гҒ“гҒ®й–ўж•°гҒҜгҖҒгғ•гӮ©гғјгғ«гғҗгғғгӮҜеҮҰзҗҶгҒ§гғ•гӮ©гғігғҲгӮ’иЁӯе®ҡгҒҷгӮӢ lua гғҶгғјгғ–гғ«гӮ’ж§ӢзҜүгҒ—гҒҫгҒҷгҖӮ гӮ°гғӘгғ•гҒҜгғӘгӮ№гғҲгҒ®жңҖеҲқгҒ®гғ•гӮ©гғігғҲгҒ§жӨңзҙўгҒ•гӮҢгҒҫгҒҷгҒҢгҖҒиҰӢгҒӨгҒӢгӮүгҒӘгҒ„е ҙеҗҲгҒҜж¬ЎгҒ®гғ•гӮ©гғігғҲгҒҢгғҒгӮ§гғғгӮҜгҒ•гӮҢгҒҫгҒҷгҖӮ The first parameter is a table listing the fonts in their preferred order: жңҖеҲқгҒ®гғ‘гғ©гғЎгғјгӮҝгҒҜгҖҒгғ•гӮ©гғігғҲгӮ’е„Әе…ҲгҒҷгӮӢй Ҷз•ӘгҒ«дёҰгҒ№гҒҹгғҶгғјгғ–гғ«гҒ§гҒҷпјҡ local wezterm = require 'wezterm' return { font = wezterm.font_with_fallback { 'JetBrains Mono', 'Noto Color Emoji' },
} гҒ“гӮҢгҒ§гҖҒиӨҮж•°гҒ®гғ•гӮ©гғігғҲгӮ’еҘҪгҒҚгҒӘгӮҲгҒҶгҒ«зө„гҒҝеҗҲгӮҸгҒӣгҒҰдҪҝз”ЁгҒҷгӮӢгҒ“гҒЁгҒҢгҒ§гҒҚгҒҫгҒҷрҹҳҢ wezterm.lua гҒҫгҒҡгҒҜгҒ“гӮ“гҒӘж„ҹгҒҳгҒ§жӣёгҒҚжҸӣгҒҲгҒҰгҒӢгӮү...гҖҒ - font = require("wezterm").font("Firge35Nerd Console"),
+ M.font = wezterm.font_with_fallback {
+ } гҒ“гҒ®гғӘгӮ№гғҲгҒ«еүҚй …гҒҫгҒ§гҒ«з”Ёж„ҸгҒ—гҒҹгғ•гӮ©гғігғҲгӮ’иҝҪеҠ гҒ—гҒҰгҒ„гҒҚгҒҫгҒҷрҹҳҪ M.font = wezterm.font_with_fallback {
+ 'Fira Code',
+ 'гғ’гғ©гӮ®гғҺи§’гӮҙгӮ·гғғгӮҜ',
+ 'Symbols Nerd Font', -- (иҮӘеҲҶгҒ§з”Ёж„ҸгҒ—гҒҹ nerd-fonts гӮ’дҪҝз”ЁгҒҷгӮӢе ҙеҗҲ) } Tip macOSгҒ®е ҙеҗҲгҒҜгҖҒгҒ•гӮүгҒ«гҒ“гӮ“гҒӘгҒ®гӮ’е…ҘгӮҢгҒҰгҒҠгҒҸгҒ®гӮӮгҒ„гҒ„гҒӢгӮӮ...вқ“ M.font = wezterm.font_with_fallback { 'Fira Code', 'гғ’гғ©гӮ®гғҺи§’гӮҙгӮ·гғғгӮҜ', 'Symbols Nerd Font',
+ 'Apple Color Emoji', } д»–гҒ®OSгҒ§гӮӮдјјгҒҹгӮҲгҒҶгҒӘгғ•гӮ©гғігғҲгӮ»гғғгғҲгҒҢгҒӮгӮӢгҒ®гҒӢгҒ©гҒҶгҒӢгҒҜгҖҒгӮҸгҒҹгҒ—гҒҢгӮҲгҒҸзҹҘгӮүгҒӘгҒ„гҒ®гҒ§гҒ”гӮҒгӮ“гҒӘгҒ•гҒ„рҹҳҝ з¶әйә—гҒ«иЎЁзӨәгҒ§гҒҚгҒҹгҒӢгҒӘвқ“вҳәпёҸ

58.body:
Mouse Binding You can define mouse actions using the mouse_bindings configuration section: гғһгӮҰгӮ№гӮўгӮҜгӮ·гғ§гғігҒҜгҖҒmouse_bindingsиЁӯе®ҡгӮ»гӮҜгӮ·гғ§гғігӮ’дҪҝз”ЁгҒ—гҒҰе®ҡзҫ©гҒҷгӮӢгҒ“гҒЁгҒҢгҒ§гҒҚгҒҫгҒҷ: гҒҫгҒҹгҒЎгӮҮгҒЈгҒЁгғ•гӮЎгӮӨгғ«гӮ’еҲҶгҒ‘гҒҫгҒ—гӮҮгҒҶгҖӮmousebinds.luaгҒҝгҒҹгҒ„гҒӘгҖӮ гӮӮгҒҶгҒ“гҒ®гҒҫгҒҫдёӯиә«гҒҫгҒ§жӣёгҒ„гҒЎгӮғгҒ„гҒҫгҒҷрҹҳё mousebinds.lua local act = require('wezterm').action return { mouse_bindings = { { event = { Down = { streak = 1, button = 'Left' } }, mods = 'NONE', action = act.EmitEvent 'show-title-bar', }, },
} гӮ«гӮ№гӮҝгғ гӮӨгғҷгғігғҲгҒҜevent.luaгҒ®ж–№гҒ«гҒҫгҒЁгӮҒгҒҫгҒҷгҖӮ event.lua wezterm.on('show-title-bar', function(window, pane) local overrides = window:get_config_overrides() or {} overrides.window_decorations = 'TITLE | RESIZE' window:set_config_overrides(overrides)
end) гҒ„гҒӨгӮӮйҖҡгӮҠгҖҒwezterm.luaгҒӢгӮүиӘӯгҒҝиҫјгҒҝгҒҫгҒҷгҖӮkeybindsгҒЁеҗҢгҒҳжөҒгӮҢрҹҳҢ wezterm.lua mouse_bindings = require('mousebinds').mouse_bindings, гҒ“гӮҢгҒ§дёҖеӣһеӢ•гҒӢгҒ—гҒҰгҒҝгҒҫгҒ—гӮҮгҒҶгҖӮгӮҰгӮЈгғігғүгӮҰгӮ’гӮҜгғӘгғғгӮҜгҒҷгӮӢгҒЁ...гҖҒ гӮҝгӮӨгғҲгғ«гғҗгғјгҒҢзҸҫгӮҢгҒҫгҒ—гҒҹгҖӮгӮ„гҒЈгҒҹгҒӯрҹҳҶ Tip дҫӢгҒҲгҒ°NeovimгҒҝгҒҹгҒ„гҒӘгҖҒгғһгӮҰгӮ№ж“ҚдҪңгҒ«еҜҫеҝңгҒ—гҒҰгҒ„гӮӢгӮўгғ—гғӘгӮұгғјгӮ·гғ§гғігӮ’еӢ•гҒӢгҒ—гҒҰгӮӢжҷӮгҒ гҒЁгҖҒ гҒқгҒЎгӮүгҒ«ж“ҚдҪңгӮ’еҘӘгӮҸгӮҢгҒҰгҒ—гҒҫгҒҶгӮҲгҒҶгҒ§гҖҒгӮҝгӮӨгғҲгғ«гғҗгғјгҒҜзҸҫгӮҢгҒҫгҒӣгӮ“гҖӮ NeovimгҒ§гҒӮгӮҢгҒ°гҖҒд»ҘдёӢгҒ®гӮҲгҒҶгҒ«гҒҷгӮҢгҒ°гғһгӮҰгӮ№ж“ҚдҪңгӮ’з„ЎеҠ№еҢ–гҒ§гҒҚгӮӢгҒ®гҒ§гҖҒгҒ“гҒ®зҠ¶ж…ӢгҒӘгӮүгғҗгғғгғҒгғӘгҒ§гҒҷрҹ‘Қ vim.api.nvim_set_option('mouse', '') гҒҹгҒ гҖҒгғһгӮҰгӮ№ж“ҚдҪңгҒ§жүӢи»ҪгҒ«ж–Үз« гӮ’жӢҫгҒ„гҒҹгҒ„гҒ“гҒЁгҒҢгҒӮгӮӢгҒ®гҒ§гҖҒгӮҸгҒҹгҒ—гҒҜе…ҘгӮҢгҒҰгҒҫгҒӣгӮ“рҹҘі гҒ§гӮӮгҒ“гӮҢгҒ гҒ‘гҒ гҒЁгҖҒеҮәгҒ—гҒҹгӮүеҮәгҒ—гҒЈгҒұгҒӘгҒ—гҒ§гҒӘгӮ“гҒӢз· гҒҫгӮҠгҒҫгҒӣгӮ“гҒӯрҹҳ® гӮ„гҒЈгҒұгӮҠд»ҠеӣһгҒҜгҒ”гӮҒгӮ“гҒӘгҒ•гҒ„гҒӢгҒӘгғјгҖӮ ...гҖӮ ...гҖӮ гҒӘгӮ“гҒҰиЁҖгҒҶгӮҸгҒ‘гҒӘгҒ„гҒҳгӮғгӮ“вҒүпёҸрҹҳқ
